"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[68963],{20447(e,t,i){i.r(t),i.d(t,{assets:()=>c,contentTitle:()=>r,default:()=>d,frontMatter:()=>s,metadata:()=>n,toc:()=>h});let n=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 37 Provisions, Contingent Liabilities and Contingent Assets/negative-low-emission-vehicle-credit-859bc1a3fd","title":"Negative Low Emission Vehicle Credits (IAS 37)","description":"July 2022","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 37 Provisions, Contingent Liabilities and Contingent Assets/Negative Low Emission Vehicle Credits (IAS 37).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 37 Provisions, Contingent Liabilities and Contingent Assets","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-37-provisions-contingent-liabili-b0bcdf04e8/negative-low-emission-vehicle-credit-859bc1a3fd","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-37-provisions-contingent-liabili-b0bcdf04e8/negative-low-emission-vehicle-credit-859bc1a3fd","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":2,"frontMatter":{"id":"negative-low-emission-vehicle-credit-859bc1a3fd","title":"Negative Low Emission Vehicle Credits (IAS 37)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-37-provisions-contingent-liabili-b0bcdf04e8/negative-low-emission-vehicle-credit-859bc1a3fd","sidebar_position":2},"sidebar":"knowledgeSidebar","previous":{"title":"Deposits relating to taxes other than income tax (IAS 37)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-37-provisions-contingent-liabili-b0bcdf04e8/deposits-relating-to-taxes-other-tha-f3f38a2b52"},"next":{"title":"Customer\u2019s Right to Receive Access to the Supplier\u2019s Software Hosted on the Cloud (IAS 38)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-ac4723e282/customer-s-right-to-receive-access-t-164bbd17bd"}}');var o=i(74848),a=i(28453);let s={id:"negative-low-emission-vehicle-credit-859bc1a3fd",title:"Negative Low Emission Vehicle Credits (IAS 37)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-37-provisions-contingent-liabili-b0bcdf04e8/negative-low-emission-vehicle-credit-859bc1a3fd",sidebar_position:2},r,c={},h=[];function l(e){let t={p:"p",strong:"strong",...(0,a.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(t.p,{children:"July 2022\nThe Committee received a request asking whether particular measures to encourage reductions in vehicle carbon emissions give rise to obligations that meet the definition of\na liability in IAS 37."}),"\n",(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.strong,{children:"The request"}),"\nThe request described government measures that apply to entities that produce or import passenger vehicles for sale in a specified market. Under the measures, entities receive\npositive credits if, in a calendar year, they have produced or imported vehicles whose average fuel emissions are lower than a government target. Entities receive negative credits if, in that year, they have produced or imported vehicles whose average fuel emissions are higher than the target."]}),"\n",(0,o.jsx)(t.p,{children:"The measures require an entity that receives negative credits for one year to eliminate these negative credits by obtaining and surrendering positive credits. The entity can obtain positive credits either by purchasing them from another entity or by generating them itself in the next year (by producing or importing more low-emission vehicles). If the entity fails to eliminate its negative credits, the government can impose sanctions on the entity. These sanctions would not require payment of fines or penalties, or any other outflow of resources embodying economic benefits, but could deny the entity opportunities in the future, for example by restricting the entity\u2019s access to the market."}),"\n",(0,o.jsx)(t.p,{children:"The request considered the position of an entity that has produced or imported vehicles with average fuel emissions higher than the government target, and asked whether such\nan entity has a present obligation that meets the definition of a liability in IAS 37."}),"\n",(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.strong,{children:"Applicable requirements"}),"\nParagraph 10 of IAS 37:\na. defines a liability as \u2018a present obligation of the entity arising from past events, the settlement of which is expected to result in an outflow from the entity of resources embodying economic benefits\u2019;\nb. distinguishes legal obligations (which derive from a contract, legislation or other operation of law) from constructive obligations (which derive from an entity\u2019s actions); and\nc. defines an obligating event as \u2018an event that creates a legal or constructive obligation that results in an entity having no realistic alternative to settling that obligation\u2019."]}),"\n",(0,o.jsx)(t.p,{children:"An entity has no realistic alternative to settling an obligation only where settlement can be enforced by law or, in the case of a constructive obligation, where the entity\u2019s actions\nhave created valid expectations in other parties that the entity will discharge the obligation (paragraph 17 of IAS 37)."}),"\n",(0,o.jsx)(t.p,{children:"The Committee observed that, in determining whether it has a liability, the entity described in the request would consider:\na. whether settling an obligation to eliminate negative credits would result in an outflow of resources embodying economic benefits;\nb. which event creates a present obligation to eliminate negative credits; and\nc. whether the entity has no realistic alternative to settling the obligation."}),"\n",(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.strong,{children:"The Committee\u2019s conclusions"}),"\nOutflow of resources embodying economic benefits\nAn entity can settle an obligation to eliminate negative credits either by purchasing credits from another entity or by generating positive credits itself in the next year. The Committee concluded that either method of settling the obligation would result in an outflow of resources embodying economic benefits. These resources are the positive\ncredits the entity would surrender to eliminate the negative balance. The entity couldotherwise have used self-generated positive credits for other purposes\u2014for example, to\nsell to other entities with negative credits."]}),"\n",(0,o.jsx)(t.p,{children:"The event that creates a present obligation\nThe definition of a liability in IAS 37 requires an entity to have a \u2018present obligation \u2026 arising from past events\u2019. Paragraph 19 of IAS 37 adds that it is only those obligations\narising from past events existing independently of an entity\u2019s future actions that meet the definition of a liability. Two IFRIC Interpretations of IAS 37 provide further relevant\nrequirements\u2014they address specific types of government-imposed charges and specify which events give rise to a present obligation for these types of charges:\na. IFRIC 6 Liabilities arising from Participating in a Specific Market\u2014Waste Electrical and Electronic Equipment addresses a charge for the cost of waste management. Legislation links the charge to an entity\u2019s participation in a specified market in a specified period. The consensus in IFRIC 6 is that an obligation arises when an entity conducts the activity to which the charge is linked.\nb. IFRIC 21 Levies addresses levies imposed by governments. The consensus in IFRIC 21 is that the event that gives rise to a liability to pay a levy is the activity that triggers the payment of the levy, as identified in the applicable legislation."}),"\n",(0,o.jsx)(t.p,{children:"In the fact pattern described in the request, the activity that triggers a requirement to eliminate negative credits (or in other words, the activity to which the measures link that\nrequirement) is the production or import of vehicles with average fuel emissions higher than the government target. If in a calendar year an entity has produced or imported\nvehicles with average fuel emissions higher than the government target, an obligation:\na. has arisen from past events.\nb. exists independently of the entity\u2019s future actions (the future conduct of its business). The entity\u2019s future actions will determine only the means by which the entity settles its present obligation\u2014whether it purchases positive credits from another entity or generates positive credits itself by producing or importing more low-emission vehicles."}),"\n",(0,o.jsx)(t.p,{children:"Therefore, the Committee concluded that, in the fact pattern described in the request, the activity that gives rise to a present obligation is the production or import of vehicles\nwhose fuel emissions, averaged for all the vehicles produced or imported in that calendar year, are higher than the government target."}),"\n",(0,o.jsx)(t.p,{children:"The Committee observed that a present obligation could arise at any date within a calendar year (on the basis of the entity\u2019s production or import activities to that date), not only at the end of the calendar year."}),"\n",(0,o.jsx)(t.p,{children:"No realistic alternative to settling an obligation\nThe Committee concluded that the measures described in the request could give rise to a legal obligation:\na. obligations that arise under the measures derive from an operation of law; and\nb. the sanctions the government can impose under the measures would be the mechanism by which settlement may be enforceable by law."}),"\n",(0,o.jsx)(t.p,{children:"An entity would have a legal obligation that is enforceable by law if accepting the possible sanctions for non-settlement is not a realistic alternative for that entity."}),"\n",(0,o.jsx)(t.p,{children:"The Committee observed that determining whether accepting sanctions is a realistic alternative for an entity requires judgement\u2014the conclusion will depend on the nature\nof the sanctions and the entity\u2019s specific circumstances."}),"\n",(0,o.jsx)(t.p,{children:"The possibility of a constructive obligation\nThe Committee concluded that, if an entity determines that it has no legal obligation to eliminate its negative credits, it would then need to consider whether it has a\nconstructive obligation to do so. It would have a constructive obligation if it has both:\na. in a calendar year, produced or imported vehicles with average fuel emissions higher than the government target; and\nb. b. taken an action that creates valid expectations in other parties that it will eliminate the resulting negative credits\u2014for example, made a sufficiently specific current statement that it will do so."}),"\n",(0,o.jsx)(t.p,{children:"Other IAS 37 requirements\nThe request asked only whether the government measures give rise to obligations that meet the definition of a liability in IAS 37. The Committee observed that, having identified such an obligation, an entity would apply other requirements in IAS 37 to determine how to measure the liability. The Committee did not discuss these other requirements."}),"\n",(0,o.jsx)(t.p,{children:"The Committee concluded that the principles and requirements in IFRS Accounting Standards provide an adequate basis for an entity to determine whether, in the fact pattern described in the request, it has an obligation that meets the definition of a liability in IAS 37. Consequently, the Committee decided not to add a standard-setting project to the work plan."})]})}function d(e={}){let{wrapper:t}={...(0,a.R)(),...e.components};return t?(0,o.jsx)(t,{...e,children:(0,o.jsx)(l,{...e})}):l(e)}},28453(e,t,i){i.d(t,{R:()=>s,x:()=>r});var n=i(96540);let o={},a=n.createContext(o);function s(e){let t=n.useContext(a);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(o):e.components||o:s(e.components),n.createElement(a.Provider,{value:t},e.children)}}}]);